295→
296→export function wireOrchestratorRoutes(
297→  wiringDeps: OrchestratorWiringDeps,
298→): {
299→  assign: RouteHandler;
300→  status: RouteHandler;
301→  accept: RouteHandler;
302→  abort: RouteHandler;
303→  review: RouteHandler;
304→  reject: RouteHandler;
305→  prompt: RouteHandler;
306→  stream?: RouteHandler;
307→} {
308→  // Lazy imports to keep module boundary clean
