310→  const queriesImport = import("../mcp/mcp-queries");
311→  const guardImport = import("./assignment-guard");
312→  const stallDetectorImport = import("./stall-detector");
313→
314→  // Helper: resolve repo_path from workspace record
315→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
316→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
317→      `SELECT repo_path FROM $ws;`,
318→      { ws: workspaceRecord },
319→    );
320→    const repoPath = rows[0]?.repo_path;
321→    if (!repoPath) {
322→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
323→    }
324→    return repoPath;
325→  };
326→
327→  // Use mock spawn for acceptance tests, production spawn otherwise
328→  const spawnAgentImport = process.env.ORCHESTRATOR_MOCK_AGENT === "true"
329→    ? Promise.resolve({
330→        createSpawnAgent: (_qfn: import("./spawn-agent").QueryFn): import("./spawn-agent").SpawnAgentFn =>
331→          () => ({
332→            messages: (async function* () {})(),
333→            abort: () => {},
334→          }),
335→      })
336→    : import("./spawn-agent");
337→
338→  const routeDeps: OrchestratorRouteDeps = {
339→    createSession: async (workspaceId, taskId, authToken) => {
340→      const [lifecycle, queries, guard, { createSpawnAgent }, stallDetector] = await Promise.all([
341→        lifecycleImport,
342→        queriesImport,
343→        guardImport,
344→        spawnAgentImport,
345→        stallDetectorImport,
346→      ]);
347→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
348→      const result = await lifecycle.createOrchestratorSession({
349→        surreal: wiringDeps.surreal,
350→        shellExec: wiringDeps.shellExec,
351→        brainBaseUrl: wiringDeps.brainBaseUrl,
352→        workspaceId,
353→        taskId,
354→        authToken,
355→        validateAssignment: guard.validateAssignment,
