368→          lifecycle.startEventIteration(
369→            {
370→              emitEvent: wiringDeps.sseRegistry.emitEvent,
371→              updateSessionStatus: async (sid, status, error) => {
372→                const rec = new RecordId("agent_session", sid);
373→                await wiringDeps.surreal.update(rec).merge({
374→                  orchestrator_status: status,
375→                  ...(error !== undefined ? { error } : {}),
376→                });
377→              },
378→              updateLastEventAt: async (sid) => {
