385→                const rec = new RecordId("agent_session", sid);
386→                const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
387→                return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
388→              },
389→              startStallDetector: (sid, stId) =>
390→                stallDetector.startStallDetector(
391→                  {
392→                    abortSession: async (abortSid) => {
393→                      const abortResult = await lifecycle.abortOrchestratorSession({
394→                        surreal: wiringDeps.surreal,
395→                        shellExec: wiringDeps.shellExec,
396→                        resolveRepoRoot,
397→                        sessionId: abortSid,
398→                        endAgentSession: queries.endAgentSession,
399→                      });
400→                      return abortResult;
401→                    },
402→                    createObservation: async () => {},
403→                    emitEvent: wiringDeps.sseRegistry!.emitEvent,
404→                  },
405→                  stallDetector.DEFAULT_STALL_CONFIG,
406→                  sid,
407→                  stId,
408→                ),
409→            },
410→            handle.messages,
411→            streamId,
412→            agentSessionId,
413→          );
414→        }
415→      }
416→
417→      return result;
418→    },
419→
420→    getSessionStatus: async (sessionId) => {
421→      const lifecycle = await lifecycleImport;
422→      return lifecycle.getOrchestratorSessionStatus({
423→        surreal: wiringDeps.surreal,
424→        sessionId,
425→      });
426→    },
427→
428→    abortSession: async (sessionId) => {
429→      const [lifecycle, queries] = await Promise.all([
430→        lifecycleImport,
431→        queriesImport,
432→      ]);
433→      return lifecycle.abortOrchestratorSession({
