454→
455→    getReview: async (sessionId) => {
456→      const [lifecycle, worktreeManager] = await Promise.all([
457→        lifecycleImport,
458→        import("./worktree-manager"),
459→      ]);
460→      return lifecycle.getOrchestratorReview({
461→        surreal: wiringDeps.surreal,
462→        sessionId,
463→        resolveRepoRoot,
464→        getDiff: (repoRoot: string, branchName: string) =>
465→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
466→        getTaskTitle: async (taskId: string) => {
467→          const { RecordId } = await import("surrealdb");
468→          const taskRecord = new RecordId("task", taskId);
469→          const rows = (await wiringDeps.surreal.query(
470→            `SELECT title FROM $task;`,
471→            { task: taskRecord },
472→          )) as Array<Array<{ title: string }>>;
473→          return rows[0]?.[0]?.title ?? "";
474→        },
475→      });
476→    },
477→
478→    rejectSession: async (sessionId, feedback) => {
479→      const lifecycle = await lifecycleImport;
480→      return lifecycle.rejectOrchestratorSession({
481→        surreal: wiringDeps.surreal,
482→        sessionId,
483→        feedback,
484→      });
485→    },
486→
