494→    },
495→  };
496→
497→  const handlers = createOrchestratorRouteHandlers(routeDeps);
498→
499→  const streamHandler = wiringDeps.sseRegistry
500→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
501→    : undefined;
502→
503→  return {
504→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
505→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
506→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
507→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
508→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
509→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
510→    prompt: withRequestLogging("orchestrator.prompt", "POST", handlers.prompt),
