  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus, TerminalOrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→
 13→// ---------------------------------------------------------------------------
 14→// Types — exported for tests
 15→// ---------------------------------------------------------------------------
 16→
 17→export type SessionDeps = {
 18→  surreal: Surreal;
 19→  shellExec: ShellExec;
 20→  brainBaseUrl: string;
 21→  spawnAgent?: SpawnAgentFn;
 22→};
 23→
 24→export type SessionErrorCode =
 25→  | "TASK_NOT_FOUND"
 26→  | "TASK_NOT_ASSIGNABLE"
 27→  | "AGENT_ALREADY_ACTIVE"
 28→  | "WORKSPACE_MISMATCH"
 29→  | "MISSING_TASK_ID"
 30→  | "WORKTREE_ERROR"
 31→  | "SESSION_NOT_FOUND"
 32→  | "SESSION_ERROR";
 33→
 34→export type SessionError = {
 35→  code: SessionErrorCode;
 36→  message: string;
 37→  httpStatus: number;
 38→};
 39→
 40→export type SessionResult<T> =
 41→  | { ok: true; value: T }
 42→  | { ok: false; error: SessionError };
 43→
 44→export type OrchestratorSessionResult = SessionResult<{
 45→  agentSessionId: string;
 46→  streamId: string;
 47→  worktreeBranch: string;
 48→}>;
 49→
 50→export type SessionStatusResult = SessionResult<{
 51→  orchestratorStatus: OrchestratorStatus;
 52→  worktreeBranch?: string;
 53→  worktreePath?: string;
 54→  lastEventAt?: string;
 55→  startedAt?: string;
 56→  error?: string;
 57→}>;
 58→
 59→export type AbortSessionResult = SessionResult<{
 60→  aborted: boolean;
 61→  sessionId: string;
 62→}>;
 63→
 64→export type AcceptSessionResult = SessionResult<{
 65→  accepted: boolean;
 66→  sessionId: string;
 67→}>;
 68→
 69→export type ReviewResult = SessionResult<{
 70→  taskTitle: string;
 71→  diff: import("./worktree-manager").DiffResult;
 72→  session: {
 73→    orchestratorStatus: string;
 74→    worktreeBranch?: string;
 75→    startedAt?: string;
 76→    lastEventAt?: string;
 77→    toolCallCount?: number;
 78→    filesEdited?: number;
 79→  };
 80→}>;
 81→
 82→export type RejectSessionResult = SessionResult<{
 83→  rejected: boolean;
 84→  continuing: boolean;
 85→}>;
 86→
 87→export type PromptSessionResult = SessionResult<{
 88→  delivered: boolean;
 89→}>;
 90→
 91→// ---------------------------------------------------------------------------
 92→// In-memory handle registry — maps agentSessionId to AgentHandle
 93→// ---------------------------------------------------------------------------
 94→
 95→const handleRegistry = new Map<string, AgentHandle>();
 96→
 97→// Exported for testing cleanup
 98→export function clearHandleRegistry(): void {
 99→  handleRegistry.clear();
100→}
101→
102→export function getHandle(sessionId: string): AgentHandle | undefined {
103→  return handleRegistry.get(sessionId);
104→}
105→
106→// ---------------------------------------------------------------------------
107→// Event iteration — port (dependencies as function signatures)
108→// ---------------------------------------------------------------------------
109→
110→export type EventIterationDeps = {
111→  emitEvent: (streamId: string, event: StreamEvent) => void;
112→  updateSessionStatus: (
113→    sessionId: string,
114→    status: OrchestratorStatus,
115→    error?: string,
116→  ) => Promise<void>;
117→  updateLastEventAt: (sessionId: string) => Promise<void>;
118→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
119→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
120→};
121→
122→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
123→  TERMINAL_ORCHESTRATOR_STATUSES,
124→);
125→
126→/**
127→ * Iterates the SDK message stream, forwarding messages through the event
128→ * bridge. Transitions session to "active" on first message, starts stall
129→ * detection, and stops on terminal status or error.
130→ *
131→ * Returns a Promise that resolves when iteration ends (for testing).
132→ * In production, this is launched fire-and-forget.
133→ */
134→export function startEventIteration(
135→  deps: EventIterationDeps,
136→  messageStream: AsyncIterable<unknown>,
137→  streamId: string,
138→  sessionId: string,
139→): Promise<void> {
140→  const stallDetector = deps.startStallDetector(sessionId, streamId);
141→
142→  const bridge = startEventBridge(
143→    {
144→      emitEvent: deps.emitEvent,
145→      updateLastEventAt: deps.updateLastEventAt,
146→    },
147→    streamId,
148→    sessionId,
149→    stallDetector,
150→  );
151→
152→  let firstMessageReceived = false;
153→
154→  async function iterate(): Promise<void> {
155→    try {
156→      for await (const rawMessage of messageStream) {
157→        // Check if session has reached terminal status
158→        const currentStatus = await deps.getSessionStatus(sessionId);
159→        if (TERMINAL_STATUSES.has(currentStatus)) {
160→          break;
161→        }
162→
163→        // Transition to active on first message
164→        if (!firstMessageReceived) {
165→          firstMessageReceived = true;
166→          await deps.updateSessionStatus(sessionId, "active");
167→        }
168→
169→        // Forward through event bridge (transform + emit + stall detection)
170→        bridge.handleMessage(rawMessage as SdkMessage);
171→      }
172→    } catch (err) {
173→      const errorMessage = err instanceof Error ? err.message : String(err);
174→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
175→    } finally {
176→      bridge.stop();
177→      handleRegistry.delete(sessionId);
178→    }
179→  }
180→
181→  return iterate();
182→}
183→
184→// ---------------------------------------------------------------------------
185→// Pure helpers
186→// ---------------------------------------------------------------------------
187→
188→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
189→  const result: Record<string, unknown> = {};
190→  for (const [key, value] of Object.entries(obj)) {
191→    if (value !== undefined) {
192→      result[key] = value;
193→    }
194→  }
195→  return result as Partial<T>;
196→}
197→
198→function sessionNotFound(sessionId: string): SessionError {
199→  return {
200→    code: "SESSION_NOT_FOUND",
201→    message: `Session not found: ${sessionId}`,
202→    httpStatus: 404,
203→  };
204→}
205→
206→function worktreeError(message: string): SessionError {
207→  return {
208→    code: "WORKTREE_ERROR",
209→    message,
210→    httpStatus: 500,
211→  };
212→}
213→
214→function fromAssignmentError(error: AssignmentError): SessionError {
215→  return {
216→    code: error.code as SessionErrorCode,
217→    message: error.message,
218→    httpStatus: error.httpStatus,
219→  };
220→}
221→
222→// ---------------------------------------------------------------------------
223→// Session row shape (DB query result)
224→// ---------------------------------------------------------------------------
225→
226→type SessionRow = {
227→  id: RecordId<"agent_session", string>;
228→  orchestrator_status?: string;
229→  worktree_branch?: string;
230→  worktree_path?: string;
231→  started_at?: string;
232→  last_event_at?: string;
233→  task_id?: RecordId<"task", string>;
234→  workspace?: RecordId<"workspace", string>;
235→  error?: string;
236→};
237→
238→type SessionLookup =
239→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
240→  | { ok: false; error: SessionError };
241→
242→async function lookupSession(
243→  surreal: Surreal,
244→  sessionId: string,
245→): Promise<SessionLookup> {
246→  const record = new RecordId("agent_session", sessionId);
247→  const session = await surreal.select<SessionRow>(record);
248→  if (!session) {
249→    return { ok: false, error: sessionNotFound(sessionId) };
250→  }
251→  if (!session.orchestrator_status) {
252→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
253→  }
254→  const status = session.orchestrator_status as OrchestratorStatus;
255→  return { ok: true, session, record, status };
256→}
257→
258→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
259→  if (!session.workspace) {
260→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
261→  }
262→  return session.workspace as RecordId<"workspace", string>;
263→}
264→
265→function generateStreamId(sessionId: string): string {
266→  return `stream-${sessionId}`;
267→}
268→
269→function slugFromTitle(title: string): string {
270→  return title
271→    .toLowerCase()
272→    .replace(/[^a-z0-9]+/g, "-")
273→    .replace(/^-|-$/g, "")
274→    .slice(0, 50);
275→}
276→
277→// ---------------------------------------------------------------------------
278→// createOrchestratorSession
279→// ---------------------------------------------------------------------------
280→
281→type CreateSessionInput = {
282→  surreal: Surreal;
283→  shellExec: ShellExec;
284→  brainBaseUrl: string;
285→  workspaceId: string;
286→  taskId: string;
287→  spawnAgent?: SpawnAgentFn;
288→  validateAssignment: (
289→    surreal: Surreal,
290→    workspaceId: string,
291→    taskId: string,
292→  ) => Promise<AssignmentResult>;
293→  createAgentSession: (input: {
294→    surreal: Surreal;
295→    agent: string;
296→    workspaceRecord: RecordId<"workspace", string>;
297→    taskId?: string;
298→  }) => Promise<{ session_id: string }>;
299→};
300→
301→export async function createOrchestratorSession(
302→  input: CreateSessionInput,
303→): Promise<OrchestratorSessionResult> {
304→  // 1. Validate assignment eligibility
305→  const assignmentResult = await input.validateAssignment(
306→    input.surreal,
307→    input.workspaceId,
308→    input.taskId,
309→  );
310→
311→  if (!assignmentResult.ok) {
312→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
313→  }
314→
315→  const { validation } = assignmentResult;
316→  const taskSlug = slugFromTitle(validation.title);
317→  const repoRoot = validation.repoPath;
318→
319→  // 2. Create worktree
320→  const worktreeResult = await createWorktree(
321→    input.shellExec,
322→    repoRoot,
323→    taskSlug,
324→  );
325→
326→  if (!worktreeResult.ok) {
327→    return {
328→      ok: false,
329→      error: worktreeError(worktreeResult.error.message),
330→    };
331→  }
332→
333→  const { branchName, worktreePath } = worktreeResult.value;
334→
335→  // 3. Create agent_session record
336→  const { session_id: agentSessionId } = await input.createAgentSession({
337→    surreal: input.surreal,
338→    agent: "claude-agent-sdk",
339→    workspaceRecord: validation.workspaceRecord,
340→    taskId: input.taskId,
341→  });
342→
343→  const streamId = generateStreamId(agentSessionId);
344→
345→  // 4. Build config and spawn agent
346→  const agentSpawnConfig: AgentSpawnConfig = {
347→    prompt: `/brain-start-task ${input.taskId}`,
348→    workDir: worktreePath,
349→    workspaceId: input.workspaceId,
350→    brainBaseUrl: input.brainBaseUrl,
351→  };
352→
353→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
354→  let handle: AgentHandle;
355→  try {
356→    handle = spawnFn(agentSpawnConfig);
357→  } catch (err) {
358→    // Rollback: remove worktree and delete agent_session on spawn failure
359→    await removeWorktree(input.shellExec, repoRoot, branchName);
360→    const sessionRecord = new RecordId("agent_session", agentSessionId);
361→    await input.surreal.delete(sessionRecord);
362→    return {
363→      ok: false,
364→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
365→    };
366→  }
367→
368→  // 5. Register handle for later abort
369→  handleRegistry.set(agentSessionId, handle);
370→
371→  // 6. Update agent_session with orchestrator fields
372→  const sessionRecord = new RecordId("agent_session", agentSessionId);
373→  await input.surreal.update(sessionRecord).merge({
374→    orchestrator_status: "spawning" as OrchestratorStatus,
375→    worktree_branch: branchName,
376→    worktree_path: worktreePath,
377→    stream_id: streamId,
378→  });
379→
380→  return {
381→    ok: true,
382→    value: {
383→      agentSessionId,
384→      streamId,
385→      worktreeBranch: branchName,
386→    },
387→  };
388→}
389→
390→// Default spawn -- placeholder for production use
391→function defaultSpawnAgent(
392→  _config: AgentSpawnConfig,
393→): AgentHandle {
394→  throw new Error(
395→    "spawnAgent not provided -- must be injected for production use",
396→  );
397→}
398→
399→// ---------------------------------------------------------------------------
400→// getOrchestratorSessionStatus
401→// ---------------------------------------------------------------------------
402→
403→type GetStatusInput = {
404→  surreal: Surreal;
405→  sessionId: string;
406→};
407→
408→export async function getOrchestratorSessionStatus(
409→  input: GetStatusInput,
410→): Promise<SessionStatusResult> {
411→  const lookup = await lookupSession(input.surreal, input.sessionId);
412→  if (!lookup.ok) {
413→    return { ok: false, error: lookup.error };
414→  }
415→  const { session } = lookup;
416→
417→  return {
418→    ok: true,
419→    value: {
420→      orchestratorStatus: lookup.status,
421→      ...pickDefined({
422→        worktreeBranch: session.worktree_branch,
423→        worktreePath: session.worktree_path,
424→        startedAt: session.started_at,
425→        lastEventAt: session.last_event_at,
426→        error: session.error,
427→      }),
428→    },
429→  };
430→}
431→
432→// ---------------------------------------------------------------------------
433→// abortOrchestratorSession
434→// ---------------------------------------------------------------------------
435→
436→type AbortSessionInput = {
437→  surreal: Surreal;
438→  shellExec: ShellExec;
439→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
440→  sessionId: string;
441→  endAgentSession: (input: {
442→    surreal: Surreal;
443→    workspaceRecord: RecordId<"workspace", string>;
444→    sessionId: string;
445→    summary: string;
446→  }) => Promise<{ session_id: string; ended: boolean }>;
447→};
448→
449→export async function abortOrchestratorSession(
450→  input: AbortSessionInput,
451→): Promise<AbortSessionResult> {
452→  const lookup = await lookupSession(input.surreal, input.sessionId);
453→  if (!lookup.ok) {
454→    return { ok: false, error: lookup.error };
455→  }
456→  const { session, record: sessionRecord } = lookup;
457→
458→  // 1. Abort the agent process if handle exists
459→  const handle = handleRegistry.get(input.sessionId);
460→  if (handle) {
461→    handle.abort();
462→    handleRegistry.delete(input.sessionId);
463→  }
464→
465→  // 2. Update orchestrator_status to aborted
466→  await input.surreal.update(sessionRecord).merge({
467→    orchestrator_status: "aborted" as OrchestratorStatus,
468→  });
469→
470→  const workspaceRecord = requireWorkspace(session, input.sessionId);
471→
472→  // 3. Remove worktree if branch name exists
473→  if (session.worktree_branch) {
474→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
475→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
476→  }
477→
478→  // 4. Return task to ready
479→  if (session.task_id) {
480→    await input.surreal.update(session.task_id).merge({
481→      status: "ready",
482→      updated_at: new Date(),
483→    });
484→  }
485→
486→  // 5. End the agent session
487→  await input.endAgentSession({
488→    surreal: input.surreal,
489→    workspaceRecord,
490→    sessionId: input.sessionId,
491→    summary: "Session aborted",
492→  });
493→
494→  return {
495→    ok: true,
496→    value: {
497→      aborted: true,
498→      sessionId: input.sessionId,
499→    },
500→  };
501→}
502→
503→// ---------------------------------------------------------------------------
504→// acceptOrchestratorSession
505→// ---------------------------------------------------------------------------
506→
507→type AcceptSessionInput = {
508→  surreal: Surreal;
509→  sessionId: string;
510→  summary: string;
511→  endAgentSession: (input: {
512→    surreal: Surreal;
513→    workspaceRecord: RecordId<"workspace", string>;
514→    sessionId: string;
515→    summary: string;
516→  }) => Promise<{ session_id: string; ended: boolean }>;
517→};
518→
519→export async function acceptOrchestratorSession(
520→  input: AcceptSessionInput,
521→): Promise<AcceptSessionResult> {
522→  const lookup = await lookupSession(input.surreal, input.sessionId);
523→  if (!lookup.ok) {
524→    return { ok: false, error: lookup.error };
525→  }
526→  const { session, record: sessionRecord, status } = lookup;
527→
528→  if (!ACCEPTABLE_STATUSES.has(status)) {
529→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
530→  }
531→
532→  const workspaceRecord = requireWorkspace(session, input.sessionId);
533→
534→  // 1. Update orchestrator_status to completed
535→  await input.surreal.update(sessionRecord).merge({
536→    orchestrator_status: "completed" as OrchestratorStatus,
537→  });
538→
539→  // 2. Mark task as done
540→  if (session.task_id) {
541→    await input.surreal.update(session.task_id).merge({
542→      status: "done",
543→      updated_at: new Date(),
544→    });
545→  }
546→
547→  // 3. Clean up handle registry
548→  handleRegistry.delete(input.sessionId);
549→
550→  // 4. End the agent session
551→  await input.endAgentSession({
552→    surreal: input.surreal,
553→    workspaceRecord,
554→    sessionId: input.sessionId,
555→    summary: input.summary,
556→  });
557→
558→  return {
559→    ok: true,
560→    value: {
561→      accepted: true,
562→      sessionId: input.sessionId,
563→    },
564→  };
565→}
566→
567→// ---------------------------------------------------------------------------
568→// State guard helpers
569→// ---------------------------------------------------------------------------
570→
571→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
572→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
573→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
574→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
575→
576→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
577→  return {
578→    code: "SESSION_ERROR",
579→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
580→    httpStatus: 409,
581→  };
582→}
583→
584→function sessionAborted(sessionId: string): SessionError {
585→  return {
586→    code: "SESSION_ERROR",
587→    message: `Session ${sessionId} has been aborted`,
588→    httpStatus: 409,
589→  };
590→}
591→
592→// ---------------------------------------------------------------------------
593→// getOrchestratorReview
594→// ---------------------------------------------------------------------------
595→
596→type GetReviewInput = {
597→  surreal: Surreal;
598→  sessionId: string;
599→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
600→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
601→  getTaskTitle: (taskId: string) => Promise<string>;
602→};
603→
604→export async function getOrchestratorReview(
605→  input: GetReviewInput,
606→): Promise<ReviewResult> {
607→  const lookup = await lookupSession(input.surreal, input.sessionId);
608→  if (!lookup.ok) {
609→    return { ok: false, error: lookup.error };
610→  }
611→  const { session, status } = lookup;
612→
613→  if (status === "aborted") {
614→    return { ok: false, error: sessionAborted(input.sessionId) };
615→  }
616→
617→  if (!REVIEWABLE_STATUSES.has(status)) {
618→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
619→  }
620→
