export function transformSdkMessage(
  message: SdkMessage,
  sessionId: string,
): StreamEvent[] {
  switch (message.type) {
    case "assistant":
      return transformAssistantContent(message.content, sessionId);

    case "result":
      return [transformResultMessage(message, sessionId)];

    default:
      return [];
  }
}

